mapper.select:
SELECT n.noti_id, n.ref_id, n.url, n.message, n.is_read, n.created_at, n.type, COUNT(*) OVER() AS total_count FROM notification n WHERE (n.member_code = #{memberCode} OR n.target_role = #{role})
AND n.is_read = #{req.isRead}
ORDER BY n.created_at DESC LIMIT #{req.size} OFFSET #{req.startIdx}
